import type { BaseComponentProps, TShirtSizes } from '../shared.ts';
/**
 * The props type for [LoadingSpinner](https://developers.hubspot.com/docs/apps/developer-platform/add-features/ui-extensibility/ui-components/standard-components/loading-spinner).
 *
 * @category Component Props
 */
export interface LoadingSpinnerProps extends BaseComponentProps {
    /**
     * The text that displays next to the spinner.
     *
     */
    label: string;
    /**
     * When set to `true`, the `label` will appear next to the spinner.
     *
     * @defaultValue `false`
     */
    showLabel?: boolean;
    /**
     * The size of the spinner.
     *
     * @defaultValue `"sm"`
     */
    size?: TShirtSizes['xs'] | TShirtSizes['sm'] | TShirtSizes['md'];
    /**
     * The position of the spinner.
     *
     * @defaultValue `"inline"`
     */
    layout?: 'inline' | 'centered';
}
